  if Sum(y) <= Sum(x) {
    GreedyKeepValid(x, Sum(y));
  } else {
    GreedyKeepSumBound(x, Sum(y));
  }
}

method PilesWithStones(x: seq<int>, y: seq<int>) returns (result: bool)
  requires |x| == |y|
  requires AllNonNeg(x)
  requires AllNonNeg(y)
  ensures result == CanTransform(x, y)
{
  var xSum := 0;
  var i := 0;
  while i < |x|
    invariant 0 <= i <= |x|
    invariant xSum == Sum(x[..i])
  {
    SumAppend(x[..i], x[i]);
    assert Sum(x[..i+1]) == xSum + x[i];
    xSum := xSum + x[i];
    i := i + 1;
  }
  assert xSum == Sum(x);  // Ensure final sum matches

  var ySum := 0;
  i := 0;
  while i < |y|
    invariant 0 <= i <= |y|
    invariant ySum == Sum(y[..i])
  {
    SumAppend(y[..i], y[i]);
    assert Sum(y[..i+1]) == ySum + y[i];
    ySum := ySum + y[i];
    i := i + 1;
  }
  assert ySum == Sum(y);  // Ensure final sum matches

  CanTransformIffSumLeq(x, y);
  result := ySum <= xSum;
}

